mapper.insert:
	INSERT INTO TBMETABS (
		 META_ENG_NM		
		,META_KOR_NM		
		,DATA_TYPE_NM		
		,META_LEN		
		,DECIMAL_LEN
		,META_ENC_YN
		,META_TERM_TYPE
	) VALUES 
	(
		 #{metaEngNm, jdbcType = VARCHAR}
 		,#{metaKorNm, jdbcType = VARCHAR}
 		,#{dataTypeNm, jdbcType = VARCHAR}
 		,#{metaLen, jdbcType = NUMERIC}
 		,#{decimalLen, jdbcType = NUMERIC}
 		,#{metaEncYn, jdbcType = VARCHAR}
 		,#{metaTermType, jdbcType = VARCHAR}
  	)

	INSERT INTO TBMETABS (
		 META_ENG_NM		
		,META_KOR_NM		
		,DATA_TYPE_NM		
		,META_LEN		
		,DECIMAL_LEN		
	) VALUES

	(
		 #{item.metaEngNm, jdbcType = VARCHAR}
 		,#{item.metaKorNm, jdbcType = VARCHAR}
 		,#{item.dataTypeNm, jdbcType = VARCHAR}
 		,#{item.metaLen, jdbcType = NUMERIC}
 		,#{item.decimalLen, jdbcType = NUMERIC}
  	)

mapper.update:
	UPDATE TBMETABS 
	SET
		META_ENG_NM = #{metaEngNm, jdbcType = VARCHAR}
  		,DATA_TYPE_NM = #{dataTypeNm, jdbcType = VARCHAR}		
  		,META_LEN = #{metaLen, jdbcType = NUMERIC}		
  		,DECIMAL_LEN = #{decimalLen, jdbcType = NUMERIC}		
  		,META_ENC_YN = #{metaEncYn, jdbcType = VARCHAR}
  		,META_TERM_TYPE = #{metaTermType, jdbcType = VARCHAR}
   	WHERE 
	   	META_KOR_NM = #{metaKorNm, jdbcType = VARCHAR}

	UPDATE TB_EAI_STD_TRM_I 
	SET
		EAI_IF_DATA_APLY_TMSTMP = #{ifDataAplyTmstmp, jdbcType = VARCHAR}
  		,EAI_IF_DATA_APLY_STS_CD = #{ifDataAplyStsCd, jdbcType = VARCHAR}		
  		,EAI_IF_DATA_APLY_ERR_CD = #{ifDataAplyErrCd, jdbcType = VARCHAR}
  		,EAI_IF_DATA_APLY_ERR_CONT = #{ifDataAplyErrMsg, jdbcType = NUMERIC}
   	WHERE 
	   	EAI_IF_DATA_SEQ_NBR = #{ifDataSeq, jdbcType = NUMERIC}

mapper.select:
SELECT C.INTRFC_ID AS intrfcId, C.INTRFC_NM AS intrfcNm, C.INTRFC_TYPE_CD AS intrfcType, A.MSG_LAYOUT_ID AS msgLayoutId FROM TBINTRFCMSGLAYOUTDT A INNER JOIN TBMSGLAYOUTDT B ON A.MSG_LAYOUT_ID = B.MSG_LAYOUT_ID INNER JOIN TBINTRFCCOMBS C ON A.INTRFC_ID = C.INTRFC_ID WHERE B.FLD_ENG_NM = #{metaEngNm, jdbcType = VARCHAR}
AND C.INTRFC_ID like CONCAT('%',#{intrfcId, jdbcType = VARCHAR},'%')
AND C.INTRFC_NM like CONCAT('%',#{intrfcNm, jdbcType = VARCHAR},'%')
